{
  "name": "ZPL Pro Studio 2026",
  "description": "A professional batch ZPL label converter and management system for high-volume label processing."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface LogEntry {
  message: string;
  timestamp: string;
}

export enum ProcessMode {
  PDF = 'pdf',
  PRINT = 'print'
}

export interface ProcessingState {
  isProcessing: boolean;
  progress: number;
  total: number;
  current: number;
  speed: number;
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Sidebar } from './components/Sidebar';
import { LogBox } from './components/LogBox';
import { ProcessMode, LogEntry, ProcessingState } from './types';
import { processZplToPdf } from './services/zplService';

const App: React.FC = () => {
  const [logs, setLogs] = useState<LogEntry[]>([{ 
    message: "System Initialized. All engines are ready.", 
    timestamp: new Date().toLocaleTimeString() 
  }]);

  const [file, setFile] = useState<File | null>(null);
  const [printer, setPrinter] = useState<string>("Zebra ZD421 (Mock)");
  const [dpi, setDpi] = useState<string>("8dpmm");
  const [labelSize, setLabelSize] = useState<string>("4x6");

  const [processing, setProcessing] = useState<ProcessingState>({
    isProcessing: false,
    progress: 0,
    total: 0,
    current: 0,
    speed: 0
  });

  const addLog = useCallback((message: string) => {
    setLogs(prev => [...prev, { 
      message: `> ${message}`, 
      timestamp: new Date().toLocaleTimeString() 
    }]);
  }, []);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      addLog(`Loaded: ${selectedFile.name}`);
    }
  };

  const runTask = async (mode: ProcessMode) => {
    if (!file) {
      alert("Please load a ZPL/TXT file first!");
      return;
    }

    setProcessing(prev => ({ ...prev, isProcessing: true, progress: 0, speed: 0 }));
    addLog(`Starting ${mode.toUpperCase()} mode processing...`);

    try {
      const text = await file.text();
      // Split ZPL by ^XA (standard logic from Python)
      const labels = text.split('^XA').filter(l => l.trim()).map(l => '^XA' + l);
      const total = labels.length;

      setProcessing(prev => ({ ...prev, total }));
      const startTime = Date.now();

      const blob = await processZplToPdf(labels, dpi, labelSize, (current) => {
        const elapsedSeconds = (Date.now() - startTime) / 1000;
        const speed = elapsedSeconds > 0 ? (current / elapsedSeconds) : 0;

        setProcessing(prev => ({
          ...prev,
          current,
          progress: (current / total) * 100,
          speed: parseFloat(speed.toFixed(1))
        }));

        if (current % 10 === 0 || current === total) {
            addLog(`Processing... ${current}/${total}`);
        }
      });

      if (blob) {
        const url = URL.createObjectURL(blob);
        if (mode === ProcessMode.PDF) {
          const link = document.createElement('a');
          link.href = url;
          link.download = `Labels_${Date.now()}.pdf`;
          link.click();
          addLog("✅ PDF Created Successfully!");
        } else {
          const printWindow = window.open(url);
          if (printWindow) {
            printWindow.onload = () => {
              printWindow.print();
            };
            addLog("✅ Sent to Print Dialog Successfully!");
          }
        }
      }
    } catch (error) {
      addLog(`Error: ${error instanceof Error ? error.message : String(error)}`);
    } finally {
      setProcessing(prev => ({ ...prev, isProcessing: false }));
    }
  };

  return (
    <div className="flex h-screen w-full overflow-hidden bg-[#121212] font-sans">
      {/* Sidebar */}
      <Sidebar 
        printer={printer}
        setPrinter={setPrinter}
        dpi={dpi}
        setDpi={setDpi}
        labelSize={labelSize}
        setLabelSize={setLabelSize}
        speed={processing.speed}
      />

      {/* Main Content */}
      <main className="flex-1 flex flex-col p-6 overflow-y-auto">
        <div className="max-w-5xl w-full mx-auto space-y-6">
          <header className="mb-8">
            <h1 className="text-3xl font-bold text-white mb-2">ZPL Ultimate Studio 2026 - JM International</h1>
            <h2 className="text-xl text-gray-400">Batch Converter & Management System</h2>
          </header>

          {/* Upload Card */}
          <section className="bg-[#1e1e1e] p-6 rounded-xl border border-[#2e2e2e] flex items-center justify-between">
            <div className="flex items-center gap-4">
              <label className="cursor-pointer bg-[#3498db] hover:bg-[#2980b9] text-white font-bold py-3 px-6 rounded transition-colors flex items-center gap-2">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
                LOAD ZPL/XT FILE
                <input type="file" className="hidden" accept=".txt,.zpl" onChange={handleFileChange} />
              </label>
              <div className="text-gray-400">
                <p className="text-sm">Status:</p>
                <p className={file ? "text-[#3498db] font-medium" : "text-gray-500 italic"}>
                  {file ? `File: ${file.name}` : "Waiting for file..."}
                </p>
              </div>
            </div>
          </section>

          {/* Control Buttons */}
          <section className="flex flex-wrap gap-4">
            <button 
              disabled={processing.isProcessing || !file}
              onClick={() => runTask(ProcessMode.PDF)}
              className="bg-[#f39c12] hover:bg-[#e67e22] disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold py-4 px-10 rounded-lg flex items-center gap-2 transition-all shadow-lg active:scale-95"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4" />
              </svg>
              SAVE PDF
            </button>
            <button 
              disabled={processing.isProcessing || !file}
              onClick={() => runTask(ProcessMode.PRINT)}
              className="bg-[#2ecc71] hover:bg-[#27ae60] disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold py-4 px-10 rounded-lg flex items-center gap-2 transition-all shadow-lg active:scale-95"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" />
              </svg>
              DIRECT PRINT
            </button>
            <button 
              onClick={() => alert("Guide:\n1. Load ZPL/TXT\n2. Configure DPI & Size\n3. Click Save or Print\nSupports 10k+ Labels!")}
              className="bg-[#333] hover:bg-[#444] text-white font-bold py-4 px-8 rounded-lg flex items-center gap-2 transition-all"
            >
              <span className="text-xl">?</span> HOW TO USE
            </button>
          </section>

          {/* Log Box Area */}
          <div className="space-y-2">
            <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider px-1">Status Box</h3>
            <LogBox logs={logs} />
          </div>

          {/* Progress Bar */}
          <div className="space-y-2">
            <div className="w-full bg-[#111] rounded-full h-3 border border-[#2e2e2e]">
              <div 
                className="bg-[#2ecc71] h-full rounded-full transition-all duration-300" 
                style={{ width: `${processing.progress}%` }}
              />
            </div>
            <p className="text-xs text-right text-gray-500">— {processing.current} / {processing.total}</p>
          </div>

          <footer className="pt-8 border-t border-[#222] text-center text-gray-500 text-sm">
            <p>Powered by <span className="text-white font-semibold">JM INTERNATIONAL</span> | Created by <span className="text-white">Rakibul Hasan Asif</span></p>
          </footer>
        </div>
      </main>

      {/* Aesthetic Star Decorative (Mirroring the Diamond/Star vibe in image) */}
      <div className="fixed bottom-8 right-8 pointer-events-none opacity-20">
         <svg width="60" height="60" viewBox="0 0 24 24" fill="white">
            <path d="M12 2L14.5 9.5H22L16 14L18.5 21.5L12 17L5.5 21.5L8 14L2 9.5H9.5L12 2Z" />
         </svg>
      </div>
    </div>
  );
};

export default App;

